use Illuminate\Support\Facades\Cache;

// Armazenar por 60 minutos
Cache::put('chave', 'valor', now()->addMinutes(60));

// Buscar (retorna null se expirado)
$valor = Cache::get('chave');

// Buscar com padrão
$valor = Cache::get('chave', 'padrão');

// Remover
Cache::forget('chave');

// Verificar se existe
if (Cache::has('chave')) { ... }

// Se a chave existir, retorna do cache.
// Se não existir, executa o callback, armazena e retorna.
$produtos = Cache::remember('produtos-destaque', now()->addHours(1), function () {
    return Produto::where('destaque', true)->with('categoria')->get();
});

// rememberForever() — sem expiração
$configuracoes = Cache::rememberForever('config-sistema', function () {
    return Configuracao::pluck('valor', 'chave')->toArray();
});
